use postgres::Client;

pub async fn search_user_by_email(email: &str) -> Result<Vec<User>, postgres::Error> {
    let mut client = Client::connect("postgres://user:password@host:port/database").await?;

    let sql = format!("SELECT * FROM users WHERE email = $1");
    let stmt = client.prepare(&sql).await?;

    let rows = client.query(&stmt, &[email]).await?;

    let users = rows.iter().map(|row| User {
        id: row.get(0),
        email: row.get(1),
        name: row.get(2),
    }).collect();

    Ok(users)
}